import { NextRequest, NextResponse } from "next/server";
import { validateNewsletterPayload } from "@/lib/newsletter/schema";
import { upsertNewsletterSubscriber, markChecklistSent } from "@/lib/newsletter/supabase";
import { sendChecklistEmail } from "@/lib/newsletter/email";
import type { NewsletterPayload } from "@/lib/newsletter/schema";

export async function POST(req: NextRequest) {
  // Parse body
  let body: unknown;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
  }

  // Validate
  const result = validateNewsletterPayload(body as NewsletterPayload);
  if (!result.ok) {
    return NextResponse.json({ error: result.error.message, field: result.error.field }, { status: 422 });
  }

  const { data } = result;

  try {
    const upsert = await upsertNewsletterSubscriber(data);

    if (upsert.status === "already_subscribed") {
      return NextResponse.json({ status: "already_subscribed" });
    }

    // New subscriber — send checklist email then mark sent
    await sendChecklistEmail(data.email, data.locale);
    await markChecklistSent(data.emailNorm);

    return NextResponse.json({ status: "subscribed" });
  } catch (err) {
    console.error("[newsletter/subscribe]", err);
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

export function GET() {
  return new NextResponse(null, { status: 405, headers: { Allow: "POST" } });
}
